+    ];
+    let sources2 = sources.clone();
+    sources.sort();
+    let mut sources3 = sources2;
+    sources3.sort();
+    assert_eq!(sources, sources3);
+    assert_eq!(sources[0], MacrotaskSource::MessageChannel);
