+fn make_entry_full(
+    id: &str,
+    domain: MismatchDomain,
+    severity: MismatchSeverity,
+    target: ComparisonTarget,
+    remediation: RemediationStatus,
+) -> MismatchEntry {
+    let mut e = make_entry(id, domain, severity);
+    e.target = target;
+    e.remediation = remediation;
