+#[test]
+fn enrichment_region_state_all_display_unique() {
+    let displays: BTreeSet<String> = [
+        RegionState::Running,
+        RegionState::CancelRequested,
+        RegionState::Draining,
+        RegionState::Finalizing,
+        RegionState::Closed,
+    ]
